#include <bits/stdc++.h>
using namespace std;

const int N=5e5+10,M=4e6+10;

int n,m,cnt;
int head[N],ver[M],nxt[M],tot=1;
int dfn[N],low[N],num,stk[N],top;
vector<int> vcc[N];

void add(int u,int v){
    ver[++tot]=v,nxt[tot]=head[u],head[u]=tot;
    ver[++tot]=u,nxt[tot]=head[v],head[v]=tot;
}

void tarjan(int x){
    dfn[x]=low[x]=++num;
    if(head[x]==0){
        cnt++;
        vcc[cnt].push_back(x);
        return;
    }
    stk[++top]=x;
    for(int i=head[x];i;i=nxt[i])
        if(!dfn[ver[i]]){
            int y=ver[i];
            tarjan(y);
            low[x]=min(low[x],low[y]);
            if(low[y]>=dfn[x]){
                cnt++;
                int z;
                do{
                    z=stk[top--],vcc[cnt].push_back(z);
                }while(z!=y);
                vcc[cnt].push_back(x);
            }
        }else
            low[x]=min(low[x],dfn[ver[i]]);
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,u,v;i<=m;i++){
        scanf("%d%d",&u,&v);
        if(u!=v) add(u,v);
    }
    for(int i=1;i<=n;i++)
        if(!dfn[i]){
            top=0;
            tarjan(i);
        }
    printf("%d\n",cnt);
    for(int i=1;i<=cnt;i++){
        printf("%d",vcc[i].size());
        for(int j:vcc[i])
            printf(" %d",j);
        puts("");
    }
    return 0;
}
